const response = $input.first().json;
const content = response.content[0].text;

const cleanJson = content
  .replace(/```json\n?/g, '')
  .replace(/```\n?/g, '')
  .trim();

let scriptData;
try {
  scriptData = JSON.parse(cleanJson);
} catch(e) {
  throw new Error('Claude 응답 파싱 실패: ' + content);
}

const scenes = scriptData.scenes;
const results = [];

for (const scene of scenes) {
  results.push({
    json: {
      title: scriptData.title,
      concept: scriptData.concept,
      bgm_mood: scriptData.bgm_mood,
      srt_content: scriptData.srt_content,
      total_scenes: scenes.length,
      scene_number: scene.scene_number,
      duration_sec: scene.duration_sec,
      narration: scene.narration,
      image_prompt_en: scene.image_prompt_en,
      subtitle: scene.subtitle,
      date_str: new Date().toISOString().split('T')[0]
    }
  });
}

const scriptText = [
  `📅 날짜: ${results[0].json.date_str}`,
  `🎬 제목: ${scriptData.title}`,
  `💡 컨셉: ${scriptData.concept}`,
  `🎵 BGM 분위기: ${scriptData.bgm_mood}`,
  ``,
  `========================================`,
  `씬별 스크립트`,
  `========================================`,
  ...scenes.map(s =>
    `[씬 ${s.scene_number}] (${s.duration_sec}초)\n나레이션: ${s.narration}\n자막: ${s.subtitle}`
  ),
  ``,
  `========================================`,
  `SRT 자막`,
  `========================================`,
  scriptData.srt_content
].join('\n\n');

results.forEach(r => { r.json.script_text = scriptText; });

return results;

